            // Scale the coordinates
            Vector2[] scaledCorners = new Vector2[originalCorners.Length];
            for (int i = 0; i < originalCorners.Length; i++)
            {
                scaledCorners[i] = new Vector2(
                    originalCorners[i].X * PreferredBackBufferWidth / 2560,
