            {"cloth", "bolt"}, {"wood", "log"}, {"stone", "stone"}, {"ore", "ore"},
            {"metal", "bar"}, {"gemstone", "gemstone"}, {"sand", "pile"},
            {"fiber", "bunch"}, {"ice", "block"}, {"glass", "sheet"}
        };

                    var currentRecipeMaterials = Recipes[RecipeIndex].Item2
